import { inject, Injectable } from '@angular/core';
import { EventName, MessageBusService } from '@zdc/main';
import { firstValueFrom } from 'rxjs';

@Injectable({
  providedIn: 'root',
})
export class ClientBridgeService {
  private readonly messageBusService = inject(MessageBusService);

  /** Specific */

  getStudent(): Promise<unknown> {
    return firstValueFrom(
      this.messageBusService.emitRequest(EventName.GET_STUDENT),
    );
  }

  getParent(): Promise<unknown> {
    return firstValueFrom(
      this.messageBusService.emitRequest(EventName.GET_PARENT),
    );
  }

  getAccessToken(): Promise<unknown> {
    return firstValueFrom(
      this.messageBusService.emitRequest(EventName.GET_ACCESS_TOKEN),
    );
  }

  getSchool(): Promise<unknown> {
    return firstValueFrom(
      this.messageBusService.emitRequest(EventName.GET_SCHOOL),
    );
  }

  gotoPaymentSummary(data: unknown): Promise<unknown> {
    return firstValueFrom(
      this.messageBusService.emitRequest(EventName.GOTO_PAYMENT_SUMMARY, data),
    );
  }

  /** Generic */

  get(): Promise<unknown> {
    return firstValueFrom(
      this.messageBusService.emitRequest(EventName.GET_STUDENT),
    );
  }

  send(data: unknown): Promise<unknown> {
    return firstValueFrom(
      this.messageBusService.emitRequest(EventName.SEND, data),
    );
  }

  goto(data: unknown): Promise<unknown> {
    return firstValueFrom(
      this.messageBusService.emitRequest(EventName.GOTO, data),
    );
  }
}
